const AM: DrillQ[] = [
  {q:"Alpha represents:",options:["Market return","Excess return above expected for risk","Total portfolio value","Risk-free rate"],correct:1,explanation:"Alpha = actual return - expected return given beta. Measures skill.",difficulty:"easy",topic:"Portfolio Theory"},
  {q:"Beta of 1.5 means:",options:["Moves opposite","50% more volatile than market","50% less volatile","No correlation"],correct:1,explanation:"Beta >1 = amplified market moves. 1.5 = 10% market move → ~15% stock move.",difficulty:"easy",topic:"Portfolio Theory"},
  {q:"Sharpe Ratio measures:",options:["Total return","Risk-adjusted return vs risk-free","Beta only","Revenue growth"],correct:1,explanation:"Sharpe = (Return - Rf) / Std Dev. Higher = better return per unit risk.",difficulty:"medium",topic:"Portfolio Theory"},
  {q:"Diversification reduces:",options:["Systematic risk","Unsystematic / company-specific risk","All risk","Market risk"],correct:1,explanation:"Eliminates company-specific risk. Systematic (market) risk remains.",difficulty:"medium",topic:"Portfolio Theory"},
  {q:"P/E 12, growth 15%. PEG ratio?",scenario:"P/E: 12 | Growth: 15%",options:["0.5","0.8","1.25","1.8"],correct:1,explanation:"PEG = P/E / Growth = 12/15 = 0.8. Under 1.0 suggests undervalued.",difficulty:"medium",topic:"Valuation"},
  {q:"In a stock pitch, most critical element is:",options:["Company description","Catalyst - why market is wrong NOW","Company history","CEO background"],correct:1,explanation:"What matters is your differentiated view and why it will play out.",difficulty:"easy",topic:"Stock Pitches"},
  {q:"Gross margin is:",options:["(Revenue - COGS) / Revenue","NI / Revenue","EBITDA / Revenue","Revenue - All Expenses"],correct:0,explanation:"Gross Margin = Gross Profit / Revenue.",difficulty:"easy",topic:"Valuation"},
  {q:"FCF yield is:",options:["FCF / Revenue","FCF / Enterprise Value","Revenue / FCF","EBITDA / Debt"],correct:1,explanation:"FCF / EV (or Market Cap). Higher yield = cheaper on cash flow basis.",difficulty:"medium",topic:"Valuation"},
  {q:"Company with negative working capital likely:",options:["Going bankrupt","Collects cash before paying suppliers","Overpaying inventory","Losing money per sale"],correct:1,explanation:"Negative WC = favorable payment terms (Amazon, Costco model).",difficulty:"hard",topic:"Valuation"},
  {q:"EMH states:",options:["Markets always crash","Prices reflect all available info","Technical analysis works","Value always wins"],correct:1,explanation:"Stock prices incorporate all known information. Beating market consistently is very hard.",difficulty:"easy",topic:"Portfolio Theory"},
  {q:"Dollar cost averaging involves:",options:["All at once","Fixed amounts at regular intervals","Only buying dips","Timing the market"],correct:1,explanation:"Consistent investment regardless of price. Reduces timing risk.",difficulty:"easy",topic:"Portfolio Theory"},
  {q:"EV/EBITDA preferred over P/E because:",options:["Simpler","Capital structure neutral","Always higher","Uses NI"],correct:1,explanation:"Removes impact of different leverage. Fairer cross-company comparison.",difficulty:"medium",topic:"Valuation"},

  {q:"Alpha in portfolio management is:",options:["Total return","Return above the benchmark after adjusting for risk","Market return","Risk-free rate"],correct:1,explanation:"Alpha = excess return vs benchmark. Positive alpha = outperformance.",difficulty:"easy",topic:"Portfolio Theory"},
  {q:"Sharpe Ratio measures:",options:["Total return only","Risk-adjusted return (excess return / volatility)","Revenue growth","Beta"],correct:1,explanation:"Sharpe = (Portfolio Return - Risk-Free Rate) / Standard Deviation. Higher = better.",difficulty:"medium",topic:"Portfolio Theory"},
  {q:"Modern Portfolio Theory suggests diversification:",options:["Eliminates all risk","Reduces unsystematic risk but not systematic","Increases returns guaranteed","Is unnecessary"],correct:1,explanation:"Diversification eliminates company-specific risk. Market risk (beta) remains.",difficulty:"medium",topic:"Portfolio Theory"},
  {q:"A stock with P/E of 30x vs industry avg of 15x suggests:",options:["It's definitely overvalued","Market expects higher growth","It's bankrupt","P/E doesn't matter"],correct:1,explanation:"High P/E = market pricing in higher growth or lower risk. Could be justified or not.",difficulty:"medium",topic:"Valuation"},
  {q:"Free Cash Flow Yield equals:",options:["FCF / Revenue","FCF / Market Cap","EBITDA / EV","Net Income / Share Price"],correct:1,explanation:"FCF Yield = FCF / Market Cap. Higher yield = more cash per dollar of market value.",difficulty:"medium",topic:"Valuation"},
  {q:"In a stock pitch, you must include:",options:["Only the price target","Thesis, catalysts, valuation, and risks","Just the company name","Historical prices only"],correct:1,explanation:"Strong pitch: what's mispriced, why now (catalysts), how you value it, what could go wrong.",difficulty:"easy",topic:"Stock Pitches"},
  {q:"A catalyst in a stock pitch is:",options:["A chemical compound","A specific event that will unlock value","The current stock price","A type of fund"],correct:1,explanation:"Catalyst = specific near-term event: earnings surprise, new product, management change, M&A.",difficulty:"easy",topic:"Stock Pitches"},
  {q:"Long/short equity strategy means:",options:["Only buying stocks","Buying undervalued stocks AND shorting overvalued ones","Only shorting","Buying bonds"],correct:1,explanation:"Long winners + short losers. Profits from relative performance, partially hedged.",difficulty:"easy",topic:"Portfolio Theory"},
  {q:"What does it mean to be 'overweight' a sector?",options:["Holding less than benchmark weight","Holding more than benchmark weight","Not holding any","Selling the sector"],correct:1,explanation:"Overweight = allocating more than the benchmark. Active bet that sector will outperform.",difficulty:"easy",topic:"Portfolio Theory"},
  {q:"EV/FCF is preferred over P/E when:",options:["Company has no debt","Company has significant debt or capex differences","P/E is always better","Company is private"],correct:1,explanation:"EV/FCF is capital structure neutral and captures actual cash generation after reinvestment.",difficulty:"hard",topic:"Valuation"},
  {q:"A stock trading at 52-week low is:",options:["Always a buy","Potentially undervalued but needs fundamental analysis","Always a sell","Guaranteed to bounce"],correct:1,explanation:"Low price alone means nothing. Need to understand why - fundamentals may have deteriorated.",difficulty:"medium",topic:"Stock Pitches"},
  {q:"Growth investing focuses on:",options:["Low P/E stocks","Companies with high revenue/earnings growth potential","Only dividend stocks","Distressed companies"],correct:1,explanation:"Growth investors pay premium multiples for companies expected to grow faster than the market.",difficulty:"easy",topic:"Portfolio Theory"},
  {q:"Value investing focuses on:",options:["Fastest growing companies","Stocks trading below intrinsic value","Only tech stocks","Momentum trading"],correct:1,explanation:"Value investors buy when market price < estimated intrinsic value. Margin of safety.",difficulty:"easy",topic:"Portfolio Theory"},
  {q:"Tracking error measures:",options:["Trading mistakes","Deviation of portfolio returns from benchmark","Data errors","Order execution speed"],correct:1,explanation:"Tracking error = std dev of (portfolio return - benchmark return). Lower = closer to index.",difficulty:"medium",topic:"Portfolio Theory"},
  {q:"A short squeeze happens when:",options:["Stock price drops rapidly","Heavily shorted stock rises, forcing shorts to cover and pushing price higher","Market closes","Dividends are paid"],correct:1,explanation:"Short sellers must buy to close positions, creating more buying pressure → price spikes.",difficulty:"medium",topic:"Stock Pitches"},
  {q:"DCF is most appropriate for valuing:",options:["Early-stage startups with no revenue","Mature companies with predictable cash flows","Companies in bankruptcy","Commodities"],correct:1,explanation:"DCF needs reliable cash flow projections. Best for stable, established businesses.",difficulty:"easy",topic:"Valuation"},
  {q:"What is a margin of safety?",options:["Extra insurance on a portfolio","Buying at a price below estimated intrinsic value","A type of stop loss","A regulatory requirement"],correct:1,explanation:"Margin of safety = the gap between intrinsic value and purchase price. Protects against errors.",difficulty:"easy",topic:"Valuation"},
  {q:"Information ratio measures:",options:["How much data you have","Active return per unit of active risk","Trading volume","Market cap"],correct:1,explanation:"IR = Alpha / Tracking Error. Higher = more efficient active management.",difficulty:"hard",topic:"Portfolio Theory"},
];

