const RX: DrillQ[] = [
  {q:"Chapter 11 bankruptcy allows a company to:",options:["Liquidate immediately","Reorganize while continuing operations","Avoid all debts permanently","Merge with a competitor"],correct:1,explanation:"Chapter 11 = reorganization. Company continues operating while restructuring its debts.",difficulty:"easy",topic:"Bankruptcy"},
  {q:"Chapter 7 bankruptcy means:",options:["Reorganization","Liquidation - assets sold to repay creditors","Tax exemption","New equity issuance"],correct:1,explanation:"Chapter 7 = liquidation. Company ceases operations, assets sold, proceeds distributed.",difficulty:"easy",topic:"Bankruptcy"},
  {q:"DIP financing stands for:",options:["Direct Investment Program","Debtor-in-Possession financing","Dividend Investment Plan","Discounted Interest Payment"],correct:1,explanation:"DIP financing = new loans to a bankrupt company. Super-priority status - repaid first.",difficulty:"medium",topic:"Bankruptcy"},
  {q:"Absolute priority rule means:",options:["All creditors are equal","Senior claims must be paid in full before junior claims receive anything","Equity always gets paid first","Management decides who gets paid"],correct:1,explanation:"Secured → unsecured → subordinated → preferred → common equity. Strict waterfall.",difficulty:"medium",topic:"Bankruptcy"},
  {q:"A credit default swap (CDS) is:",options:["A type of stock","Insurance against a borrower defaulting","A cash deposit","An equity swap"],correct:1,explanation:"CDS buyer pays premium; seller pays out if reference entity defaults. Like insurance.",difficulty:"medium",topic:"Capital Structure"},
  {q:"Fulcrum security is:",options:["The most senior debt","The security class where value breaks - partially impaired","Common equity","A type of bond"],correct:1,explanation:"Fulcrum = the tranche that's partially in/out of the money. Key to restructuring negotiations.",difficulty:"hard",topic:"Capital Structure"},
  {q:"Recovery rate refers to:",options:["How fast a company grows","Cents on the dollar a creditor receives in default","Employee retention rate","Revenue recovery after recession"],correct:1,explanation:"Recovery rate = % of face value recovered. Senior secured typically 60-80%, unsecured 20-40%.",difficulty:"medium",topic:"Capital Structure"},
  {q:"A distressed exchange is:",options:["Trading stocks on a foreign exchange","Creditors swap existing debt for new securities at a discount","Employee stock exchange","Currency swap"],correct:1,explanation:"Company offers creditors new debt/equity worth less than face value to avoid formal bankruptcy.",difficulty:"hard",topic:"Capital Structure"},
  {q:"Liquidation value is:",options:["Enterprise value","What assets would sell for if the company is dissolved","Revenue projection","Book value"],correct:1,explanation:"Liquidation value = sum of individual asset sale values. Floor for creditor recovery.",difficulty:"easy",topic:"Valuation"},
  {q:"Reorganization value is:",options:["Liquidation value","Going-concern value of the restructured company","Historical cost","Book value of equity"],correct:1,explanation:"Reorg value = DCF of restructured entity as a going concern. Usually > liquidation value.",difficulty:"medium",topic:"Valuation"},
  {q:"If reorganization value > liquidation value, the company should:",options:["Liquidate (Chapter 7)","Reorganize (Chapter 11)","Do nothing","Issue more debt"],correct:1,explanation:"If worth more alive than dead, reorganize. Preserves going-concern value.",difficulty:"easy",topic:"Valuation"},
  {q:"An out-of-court restructuring is preferred because:",options:["It's always successful","Faster, cheaper, less public than formal bankruptcy","Courts are never involved","Creditors have no say"],correct:1,explanation:"Out-of-court avoids legal costs, public disclosure, and customer/supplier disruption.",difficulty:"medium",topic:"Bankruptcy"},
  {q:"Section 363 sale in bankruptcy:",options:["Is a reorganization plan","Allows sale of assets free and clear of liens","Is a type of DIP loan","Cancels all debts"],correct:1,explanation:"363 sale = quick asset sale in Chapter 11. Buyer gets clean title. Often used for going-concern sales.",difficulty:"hard",topic:"Bankruptcy"},
  {q:"Covenant violations typically lead to:",options:["Automatic liquidation","Lender can accelerate the debt or renegotiate terms","Nothing happens","Stock price increases"],correct:1,explanation:"Violation gives lenders leverage: waiver (often with fees), amendment, or acceleration.",difficulty:"medium",topic:"Capital Structure"},
  {q:"A revolver draw in distress signals:",options:["Company is healthy","Company is burning cash and needs liquidity","Company has excess cash","Company is paying dividends"],correct:1,explanation:"Drawing the revolver = cash is tight. Red flag for lenders and investors.",difficulty:"medium",topic:"Capital Structure"},
  {q:"Equitization of debt means:",options:["Converting equity to debt","Converting debt to equity - creditors become shareholders","Paying off all debt","Issuing new debt"],correct:1,explanation:"Creditors swap debt claims for equity ownership in the restructured company.",difficulty:"medium",topic:"Capital Structure"},
  {q:"Make-whole provisions in bonds:",options:["Allow free prepayment","Require borrower to compensate lender for lost interest if prepaid early","Guarantee full recovery","Are only in equity"],correct:1,explanation:"Make-whole = prepayment penalty. Protects bondholders from losing expected interest income.",difficulty:"hard",topic:"Capital Structure"},
  {q:"In RX, a 'priming' transaction means:",options:["Adding cosmetic improvements","New debt is placed senior to existing debt without consent","Refinancing at lower rate","Paying off all creditors"],correct:1,explanation:"Priming = new debt jumps the priority queue. Controversial - existing lenders are subordinated.",difficulty:"hard",topic:"Capital Structure"},
  {q:"A plan of reorganization must be approved by:",options:["Management only","2/3 in amount and 1/2 in number of each impaired class","All creditors unanimously","The SEC"],correct:1,explanation:"Voting threshold: 2/3 of claim amount + majority in number per impaired class.",difficulty:"hard",topic:"Bankruptcy"},
  {q:"Adequate protection in bankruptcy protects:",options:["The debtor's management","Secured creditors from loss of collateral value during bankruptcy","Unsecured creditors only","Equity holders"],correct:1,explanation:"Secured creditors may receive cash payments or replacement liens to offset collateral depreciation.",difficulty:"hard",topic:"Bankruptcy"},
  {q:"Zone of insolvency means:",options:["Company is fully solvent","Company approaches insolvency - fiduciary duty shifts to include creditors","Company has filed Chapter 7","Company has excess cash"],correct:1,explanation:"Near insolvency, board's duty expands from shareholders to also consider creditor interests.",difficulty:"hard",topic:"Bankruptcy"},
  {q:"A cramdown in bankruptcy means:",options:["Court forces a plan on dissenting creditor classes","All creditors agree","Company liquidates","Debt is forgiven entirely"],correct:0,explanation:"Court confirms plan over objection of impaired classes if it's fair, equitable, and feasible.",difficulty:"hard",topic:"Bankruptcy"},
  {q:"Debtor-in-possession means:",options:["Company's assets are seized","Existing management continues to run the business during Chapter 11","A new CEO is appointed by the court","Creditors take over operations"],correct:1,explanation:"In Chapter 11, existing management (the debtor) retains control unless a trustee is appointed.",difficulty:"easy",topic:"Bankruptcy"},
  {q:"Interest coverage ratio below 1.0x means:",options:["Company can easily pay interest","EBITDA doesn't cover interest payments","Company has no debt","Company is highly profitable"],correct:1,explanation:"ICR = EBITDA / Interest. Below 1.0x = operating income can't cover interest. Distress signal.",difficulty:"medium",topic:"Capital Structure"},
  {q:"Why do RX bankers focus on the capital structure waterfall?",options:["It's simple to calculate","It determines who gets paid what in a restructuring","It's not important","Only equity matters"],correct:1,explanation:"The waterfall determines recovery for each class. Drives all negotiation and valuation.",difficulty:"easy",topic:"Capital Structure"},
];

